return items.map(item => {
  let rawOutput = item.json.output || "";

  try {
    let fixedOutput = rawOutput;

    // 1. Extract JSON block more safely
    const start = fixedOutput.indexOf('{');
    const end = fixedOutput.lastIndexOf('}');

    if (start === -1 || end === -1) {
      throw new Error("No JSON structure found");
    }

    fixedOutput = fixedOutput.substring(start, end + 1);

    // 2. Remove broken trailing quotes (common AI cut issue)
    const quoteCount = (fixedOutput.match(/"/g) || []).length;
    if (quoteCount % 2 !== 0) {
      // remove last quote to balance
      fixedOutput = fixedOutput.slice(0, fixedOutput.lastIndexOf('"'));
      fixedOutput += '"';
    }

    const parsedData = JSON.parse(fixedOutput);

    return {
      json: {
        subject: parsedData.subject || "No Subject Found",
        email_body: parsedData.email_body || "No Body Found"
      }
    };

  } catch (error) {

    // fallback extraction
    const subjectMatch = rawOutput.match(/Subject:\s*(.+)/i) 
      || rawOutput.match(/"subject":\s*"([^"]+)"/);

    const bodyMatch = rawOutput.match(/(?:\n\n|\r\n\r\n)([\s\S]*)/);

    return {
      json: {
        error: "Partial Parse",
        subject: subjectMatch ? (subjectMatch[1] || subjectMatch[0]) : "Could not extract subject",
        email_body: bodyMatch ? bodyMatch[1].trim() : "The AI output was cut off and could not be recovered."
      }
    };
  }
});

const allResults = [];

// Process every incoming item
for (const item of $input.all()) {
  const emailFields = ['email_1', 'email_2', 'email_3'];

  emailFields.forEach(field => {
    const value = item.json[field];

    // Create a NEW individual item for every non-empty email
    if (value && typeof value === 'string' && value.trim() !== "") {
      allResults.push({
        json: { 
          email: value.trim(),
          original_field: field // Optional: keeps track of which field it came from
        }
      });
    }
  });
}

return allResults;

